 1→import React from 'react';
 2→import { View } from 'react-native';
 3→import type {
 4→  SDUIScreen,
 5→  SDUIComponent,
 6→  SDUIComponentRegistry,
 7→  SDUIContext,
 8→} from '../models';
 9→import { interpolateDeep } from '../utils/interpolation';
10→import { evaluateRule } from '../utils/jsonLogic';
11→import { getDefaultRegistry, getRenderer } from '../registry';
12→import FallbackComponent from './FallbackComponent';
13→
14→interface ScreenRendererProps {
15→  screen: SDUIScreen;
16→  registry?: SDUIComponentRegistry;
17→}
18→
19→function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
20→  if (!component.visible) return true;
21→  return evaluateRule(component.visible.rule, context);
22→}
23→
24→function renderComponent(
25→  component: SDUIComponent,
26→  context: SDUIContext,
27→  registry: SDUIComponentRegistry,
28→  key: string,
29→) {
30→  if (!isVisible(component, context)) return null;
31→
32→  const interpolatedProps = interpolateDeep(component.props, context);
33→
34→  const Renderer = getRenderer(registry, component.type);
35→
36→  if (!Renderer) {
37→    return (
38→      <FallbackComponent
39→        key={key}
40→        type={component.type}
41→        props={interpolatedProps}
42→      />
43→    );
44→  }
45→
46→  return <Renderer key={key} props={interpolatedProps} context={context} />;
47→}
48→
49→export default function ScreenRenderer({
50→  screen,
51→  registry,
52→}: ScreenRendererProps) {
53→  const activeRegistry = registry ?? getDefaultRegistry();
54→  const { context, header, body, footer } = screen;
55→
56→  return (
57→    <View style={{ flex: 1 }}>
58→      {header && renderComponent(header, context, activeRegistry, 'header')}
59→
60→      <View style={{ flex: 1 }}>
61→        {(body ?? []).map((component, index) =>
62→          renderComponent(
63→            component,
64→            context,
65→            activeRegistry,
66→            `${component.type}-${index}`,
67→          ),
68→        )}
69→      </View>
70→
71→      {footer && renderComponent(footer, context, activeRegistry, 'footer')}
72→    </View>
73→  );
74→}
