  1→import type {
  2→  SDUIContext,
  3→  SDUIRule,
  4→  SDUILogicOperand,
  5→  SDUIVarOperator,
  6→  SDUILogicPrimitive,
  7→} from '../models';
  8→import { resolveContextPath } from './interpolation';
  9→
 10→const MAX_DEPTH = 20;
 11→
 12→const COMPARISON_OPS = new Set(['==', '!=', '>', '<', '>=', '<=']);
 13→
 14→function isVarOperator(operand: SDUILogicOperand): operand is SDUIVarOperator {
 15→  return (
 16→    operand !== null &&
 17→    typeof operand === 'object' &&
 18→    'var' in operand &&
 19→    typeof (operand as SDUIVarOperator).var === 'string'
 20→  );
 21→}
 22→
 23→function isPrimitive(value: unknown): value is SDUILogicPrimitive {
 24→  return (
 25→    value === null ||
 26→    typeof value === 'string' ||
 27→    typeof value === 'number' ||
 28→    typeof value === 'boolean'
 29→  );
 30→}
 31→
 32→function resolveOperand(
 33→  operand: SDUILogicOperand,
 34→  context: SDUIContext,
 35→  depth: number,
 36→): SDUILogicPrimitive {
 37→  if (isPrimitive(operand)) return operand;
 38→  if (isVarOperator(operand)) {
 39→    const resolved = resolveContextPath(context, operand.var);
 40→    if (isPrimitive(resolved)) return resolved;
 41→    return null;
 42→  }
 43→  return evaluate(operand as SDUIRule, context, depth + 1);
 44→}
 45→
 46→function evaluateComparison(
 47→  operator: string,
 48→  operands: [SDUILogicOperand, SDUILogicOperand],
 49→  context: SDUIContext,
 50→  depth: number,
 51→): boolean {
 52→  const left = resolveOperand(operands[0], context, depth);
 53→  const right = resolveOperand(operands[1], context, depth);
 54→
 55→  switch (operator) {
 56→    case '==':
 57→      return left == right; // eslint-disable-line eqeqeq
 58→    case '!=':
 59→      return left != right; // eslint-disable-line eqeqeq
 60→    case '>':
 61→      if (typeof left !== 'number' || typeof right !== 'number') return false;
 62→      return left > right;
 63→    case '<':
 64→      if (typeof left !== 'number' || typeof right !== 'number') return false;
 65→      return left < right;
 66→    case '>=':
 67→      if (typeof left !== 'number' || typeof right !== 'number') return false;
 68→      return left >= right;
 69→    case '<=':
 70→      if (typeof left !== 'number' || typeof right !== 'number') return false;
 71→      return left <= right;
 72→    default:
 73→      return false;
 74→  }
 75→}
 76→
 77→function evaluate(rule: SDUIRule, context: SDUIContext, depth: number): boolean {
 78→  if (!rule || typeof rule !== 'object') return false;
 79→  if (depth > MAX_DEPTH) return false;
 80→
 81→  const keys = Object.keys(rule);
 82→  if (keys.length === 0) return false;
 83→
 84→  const operator = keys[0];
 85→  const operands = (rule as Record<string, unknown>)[operator];
 86→
 87→  if (operator === 'and') {
 88→    if (!Array.isArray(operands)) return false;
 89→    return (operands as SDUIRule[]).every(sub => evaluate(sub, context, depth + 1));
 90→  }
 91→
 92→  if (operator === 'or') {
 93→    if (!Array.isArray(operands)) return false;
 94→    return (operands as SDUIRule[]).some(sub => evaluate(sub, context, depth + 1));
 95→  }
 96→
 97→  if (operator === '!') {
 98→    const inner = Array.isArray(operands) ? operands[0] : operands;
 99→    return !evaluate(inner as SDUIRule, context, depth + 1);
100→  }
101→
102→  if (COMPARISON_OPS.has(operator)) {
103→    if (!Array.isArray(operands) || operands.length !== 2) return false;
104→    return evaluateComparison(
105→      operator,
106→      operands as [SDUILogicOperand, SDUILogicOperand],
107→      context,
108→      depth,
109→    );
110→  }
111→
112→  return false;
113→}
114→
115→export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
116→  return evaluate(rule, context, 0);
117→}
